import { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { detectDelimiter, generateFingerprint } from '../services/processingService';
import { extractDataFromVisual } from '../services/geminiService';
import { FileModel } from '../types';

interface UseFileProcessingProps {
    activeFile: { content: string; fileName: string; rawFile?: File } | null;
    initialModel?: FileModel;
    isImage: boolean;
    isPdf: boolean;
}

export const useFileProcessing = ({ activeFile, initialModel, isImage, isPdf }: UseFileProcessingProps) => {
    const [gridData, setGridData] = useState<string[][]>([]);
    const [isGridLoading, setIsGridLoading] = useState(false);
    const [isAiProcessing, setIsAiProcessing] = useState(false);
    const [activeMapping, setActiveMapping] = useState<any>(null);
    const [detectedFingerprint, setDetectedFingerprint] = useState<any>(null);

    // Ref para evitar loops de processamento do mesmo arquivo
    const lastProcessedFileRef = useRef<string | null>(null);

    useEffect(() => {
        if (!activeFile) {
            setGridData([]);
            setActiveMapping(null);
            lastProcessedFileRef.current = null;
            return;
        }

        // Evita re-processar se for o mesmo arquivo (proteção contra loops de estado)
        const fileKey = `${activeFile.fileName}-${activeFile.content?.length || 0}`;
        if (lastProcessedFileRef.current === fileKey) return;
        lastProcessedFileRef.current = fileKey;

        const loadContent = async () => {
            setIsGridLoading(true);
            setIsAiProcessing(false);
            let loadedRows: string[][] = [];

            try {
                if (isImage && activeFile.rawFile) {
                    setIsAiProcessing(true);
                    const aiResult = await extractDataFromVisual(activeFile.rawFile);
                    try {
                        const parsed = JSON.parse(aiResult);
                        if (parsed?.rows) {
                            loadedRows = parsed.rows.map((r: any) => [
                                String(r.date || ''),
                                String(r.description || ''),
                                r.amount ? String(r.amount) : '',
                                String(r.reference || '')
                            ]);

                            // Define mapeamento padrão para saída da IA
                            setActiveMapping({
                                dateColumnIndex: 0,
                                descriptionColumnIndex: 1,
                                amountColumnIndex: 2,
                                typeColumnIndex: 3,
                                skipRowsStart: 0
                            });
                        }
                    } catch (e) {
                        console.error("Erro ao parsear resposta da IA:", e);
                    }
                } else if (activeFile.rawFile && (activeFile.fileName.toLowerCase().endsWith('xls') || activeFile.fileName.toLowerCase().endsWith('xlsx'))) {
                    const buffer = await activeFile.rawFile.arrayBuffer();
                    const wb = XLSX.read(new Uint8Array(buffer), { type: 'array' });
                    loadedRows = XLSX.utils.sheet_to_json<string[]>(wb.Sheets[wb.SheetNames[0]], { header: 1, defval: '' });
                } else if (!isPdf) {
                    // Texto (CSV/TXT)
                    const content = activeFile.content || "";
                    if (content.trim()) {
                        const lines = content.split(/\r?\n/).filter((l: string) => l.trim().length > 0);
                        if (lines.length > 0) {
                            const delimiter = detectDelimiter(lines[0]);
                            loadedRows = lines.map((l: string) => l.split(delimiter));
                        }
                    }
                }

                if (loadedRows.length > 0) {
                    setGridData(loadedRows);

                    // Gera o fingerprint apenas uma vez
                    const sampleContent = activeFile.content || loadedRows.slice(0, 10).map(r => r.join(';')).join('\n');
                    const fp = generateFingerprint(sampleContent);
                    setDetectedFingerprint(fp);

                    // Se houver um modelo inicial (modo refinar), usa o mapeamento dele
                    // Senão, mantém mapeamento nulo para o usuário definir manualmente (ou IA definir se for imagem)
                    if (initialModel?.mapping) {
                        setActiveMapping(initialModel.mapping);
                    } else if (!isImage) {
                        setActiveMapping({
                            dateColumnIndex: -1,
                            descriptionColumnIndex: -1,
                            amountColumnIndex: -1,
                            skipRowsStart: 0
                        });
                    }
                }
            } catch (err) {
                console.error("Erro crítico no processamento de grid:", err);
            } finally {
                setIsGridLoading(false);
            }
        };

        loadContent();
    }, [activeFile, isPdf, isImage, initialModel]);

    return {
        gridData,
        setGridData,
        isGridLoading,
        isAiProcessing,
        activeMapping,
        setActiveMapping,
        detectedFingerprint
    };
};

import { useState, useCallback, useEffect, useRef } from 'react';
import { Transaction } from '../types';
import { DateResolver } from '../core/processors/DateResolver';
import { AmountResolver } from '../core/processors/AmountResolver';
import { NameResolver } from '../core/processors/NameResolver';
import { TypeResolver } from '../core/processors/TypeResolver';
import { RowValidator } from '../core/processors/RowValidator';

interface SafeTransaction extends Transaction {
    sourceIndex?: number;
    isValid?: boolean;
    status?: 'valid' | 'error' | 'edited' | 'ignored' | 'pending';
}

interface UseSimulationProps {
    gridData: string[][];
    activeMapping: any;
    cleaningKeywords: string[];
}

export const useSimulation = ({ gridData, activeMapping, cleaningKeywords }: UseSimulationProps) => {
    const [processedTransactions, setProcessedTransactions] = useState<SafeTransaction[]>([]);
    const [editingRowIndex, setEditingRowIndex] = useState<number | null>(null);
    const [editingRowData, setEditingRowData] = useState<SafeTransaction | null>(null);

    const isSimulatingRef = useRef(false);

    const runSimulation = useCallback(() => {
        if (!gridData || gridData.length === 0 || isSimulatingRef.current) return;

        isSimulatingRef.current = true;

        try {
            const mapping = activeMapping || {
                dateColumnIndex: -1, 
                descriptionColumnIndex: -1, 
                amountColumnIndex: -1, 
                skipRowsStart: 0
            };

            const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, typeColumnIndex, skipRowsStart } = mapping;

            const newTransactions: SafeTransaction[] = [];
            const yearAnchor = new Date().getFullYear();

            // Limitamos a simulação visual às primeiras 100 linhas por performance no modal
            const sampleData = gridData.slice(0, 100);

            sampleData.forEach((cols, index) => {
                if (!RowValidator.isPotentialRow(cols)) return;

                const isSkipped = index < (skipRowsStart || 0);
                const rawDate = cols[dateColumnIndex] || '';
                const rawDesc = cols[descriptionColumnIndex] || '';
                const rawAmount = cols[amountColumnIndex] || '';
                const rawType = typeColumnIndex !== undefined ? cols[typeColumnIndex] : '';

                let isoDate = '', amount = 0, cleanedDesc = '', finalType = '', isValid = false, status: SafeTransaction['status'] = 'pending';

                if (isSkipped) { 
                    status = 'ignored';
                    cleanedDesc = cols.join(' | ').substring(0, 50);
                } else if (dateColumnIndex !== -1 && amountColumnIndex !== -1 && descriptionColumnIndex !== -1) {
                    // Mapeamento completo disponível
                    isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
                    const amountStr = AmountResolver.clean(rawAmount);
                    amount = parseFloat(amountStr);

                    if (!!isoDate && isoDate.length >= 10 && !isNaN(amount) && rawDesc.trim().length > 0) {
                        cleanedDesc = NameResolver.clean(rawDesc, cleaningKeywords);
                        finalType = rawType ? String(rawType).trim().toUpperCase() : TypeResolver.resolveFromDescription(rawDesc);
                        isValid = true; 
                        status = 'valid';
                    } else {
                        status = 'error';
                        cleanedDesc = rawDesc || "Dados incompletos";
                    }
                } else {
                    // Mapeamento incompleto: mostra raw
                    cleanedDesc = cols.filter(c => !!c).join(' | ').substring(0, 60);
                    status = 'pending';
                }

                newTransactions.push({ 
                    id: `sim-${index}`, 
                    date: isValid ? isoDate : rawDate, 
                    description: rawDesc || "---", 
                    rawDescription: rawDesc || "---", 
                    amount, 
                    originalAmount: String(rawAmount), 
                    cleanedDescription: cleanedDesc, 
                    contributionType: finalType, 
                    sourceIndex: index, 
                    isValid, 
                    status 
                });
            });

            setProcessedTransactions(newTransactions);
        } finally {
            isSimulatingRef.current = false;
        }
    }, [gridData, activeMapping, cleaningKeywords]);

    // Roda simulação quando os dados ou o mapeamento mudarem significativamente
    useEffect(() => {
        runSimulation();
    }, [runSimulation]);

    const startEdit = (tx: SafeTransaction, idx: number) => {
        setEditingRowIndex(idx);
        setEditingRowData({ ...tx });
    };

    const saveRow = (onLearned?: (original: string[], corrected: SafeTransaction) => void) => {
        if (editingRowIndex !== null && editingRowData) {
            setProcessedTransactions(prev => {
                const n = [...prev];
                n[editingRowIndex] = { ...editingRowData, status: 'edited', isValid: true };
                return n;
            });

            if (onLearned && editingRowData.sourceIndex !== undefined) {
                onLearned(gridData[editingRowData.sourceIndex], editingRowData);
            }
            setEditingRowIndex(null);
        }
    };

    const cancelEdit = () => setEditingRowIndex(null);

    return {
        processedTransactions,
        runSimulation,
        editingRowIndex,
        editingRowData,
        setEditingRowData,
        startEdit,
        saveRow,
        cancelEdit
    };
};

